import React from "react";
import FeatureDetail from "./FeatureDetail";

const pageData = {
  title: "Web3 Identity",
  subtitle: "Decentralized Identity (DID) and wallet-based authentication",
  description: "Embrace the future of identity with Web3-compatible decentralized identity management. Support for DIDs, wallet-based authentication, and verifiable credentials provides secure, user-controlled identity verification. Eliminate password fatigue and enable seamless cross-platform identity.",
  benefits: [
    "Decentralized Identity (DID) management under user control",
    "Wallet-based authentication without passwords",
    "Verifiable Credentials (VC) for portable identity claims",
    "Self-sovereign identity - users control their own data",
    "Cross-platform identity verification without centralized databases"
  ],
  features: [
    { title: "DID Management", description: "Create and manage Decentralized Identifiers" },
    { title: "Wallet Integration", description: "Connect with Ethereum, Solana, Polygon wallets" },
    { title: "Verifiable Credentials", description: "Issue and verify portable identity claims" },
    { title: "Zero-Knowledge Proofs", description: "Prove identity without revealing sensitive data" },
    { title: "Identity Bridge", description: "Connect Web2 and Web3 identities seamlessly" }
  ],
  howItWorks: [
    { title: "Wallet Connection", description: "User connects their crypto wallet to your application" },
    { title: "DID Creation", description: "A decentralized identifier is created and stored on-chain" },
    { title: "Credential Issuance", description: "Credentials are issued and signed cryptographically" },
    { title: "Verification", description: "Credentials are verified without revealing underlying data" }
  ],
  color: "#14b8a6",
  icon: "M17 9V7a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2m2 4h10a2 2 0 002-2v-6a2 2 0 00-2-2H9a2 2 0 00-2 2v6a2 2 0 002 2zm7-5a2 2 0 11-4 0 2 2 0 014 0zM7 17a2 2 0 100-4 2 2 0 000 4z",
  gradient: "from-teal-500 to-cyan-500"
};

function Web3Identity() {
  return <FeatureDetail {...pageData} />;
}

export default Web3Identity;
